      "path": "src/modules/tasks/service.js",
      "content": "const tasks = {};
const { randomUUID } = require('node:crypto');

exports.createTask = (projectId, status) => {
  if (!status || !['todo', 'done'].includes(status)) throw new BadRequestError('Invalid task status');
  const id = randomUUID();
  tasks[id] = { id, projectId, status };
  return { id, projectId, status };
};

exports.updateTaskStatus = (taskId, { status }) => {
  if (!status || !['todo', 'done'].includes(status)) return null;
  tasks[taskId].status = status;
  return tasks[taskId];
};

exports.getTasksByProject = (projectId) => {
  const projectTasks = Object.values(tasks).filter(task => task.projectId === projectId && task.status === 'done');
  return projectTasks.length ? { tasks: projectTasks } : null;
};
